// src/context/SkillsContext.js

import React,
{
 createContext,
 useContext,
 useEffect,
 useState
}
from "react";

import { useAuth }
from "./AuthContext";

import {
 getSkills,
 addSkill,
 updateSkill,
 deleteSkill
}
from "../services/userService";


const SkillsContext =
createContext();


export function useSkills(){

 return useContext(
  SkillsContext
 );

}


export function SkillsProvider(
 { children }
){

 const { user } =
 useAuth();

 const [skills,setSkills] =
 useState([]);


 useEffect(()=>{

 async function load(){

  if(!user) return;

  const data =
  await getSkills(
   user.uid
  );

  setSkills(data);

 }

 load();

 },[user]);



 async function createSkill(skill){

  const id =
  await addSkill(
   user.uid,
   skill
  );

  setSkills(prev=>[

   ...prev,
   { id,...skill }

  ]);

 }


 async function editSkill(id,data){

  await updateSkill(
   user.uid,
   id,
   data
  );

  setSkills(prev=>

   prev.map(s=>

    s.id===id ?

    { ...s,...data }

    :

    s

   )

  );

 }


 async function removeSkill(id){

  await deleteSkill(
   user.uid,
   id
  );

  setSkills(prev=>

   prev.filter(
    s=>s.id!==id
   )

  );

 }


 return(

 <SkillsContext.Provider
 value={{

  skills,
  createSkill,
  editSkill,
  removeSkill

 }}>

 {children}

 </SkillsContext.Provider>

 );

}
